class Solution {
public:
    Solution(vector<int>& w) {
        total = accumulate(w.begin(), w.end(), 0);
        for (int i = 0; i < w.size(); i++) {
            w[i] = {w[i], total - w[i]};
        }
    }

    int pickIndex() {
        int rand_num = rand() % total;
        for (int i = 0; i < w.size(); i++) {
            if (rand_num < w[i].first) return i;
            rand_num -= w[i].first;
        }
        return w.size() - 1;
    }
private:
    int total;
};
```
